SELECT
/*+ INDEX_DESC(A PPS_PIN_INFO_PK) */
MNG_CODE, STATUS, NVL((SELECT CD_NM FROM PPS_KT_COMMON_CD WHERE TABLE_NM='PPS_PIN_INFO' AND COL='STATUS' AND CD= A.STATUS),'') STATUS_NM, PIN_GUBUN, NVL((SELECT CD_NM FROM PPS_KT_COMMON_CD WHERE TABLE_NM='PPS_PIN_INFO' AND COL='PIN_GUBUN' AND CD= A.PIN_GUBUN),'') PIN_GUBUN_NM, ONOFF_GUBUN, NVL((SELECT CD_NM FROM PPS_KT_COMMON_CD WHERE TABLE_NM='PPS_PIN_INFO' AND COL='ONOFF_GUBUN' AND CD= A.ONOFF_GUBUN),'') ONOFF_GUBUN_NM, TO_CHAR(OPEN_DATE, 'YYYY-MM-DD') OPEN_DATE, TO_CHAR(OUT_DATE, 'YYYY-MM-DD') OUT_DATE, START_PRICE, NOW_PRICE, OUT_PRICE, TO_CHAR(RCG_DATE, 'YYYY-MM-DD') RCG_DATE, TO_CHAR(CR_DATE, 'YYYY-MM-DD') CR_DATE, TO_CHAR(EXPIRE_DATE, 'YYYY-MM-DD') EXPIRE_DATE, OUT_AGENT_ID, F_GET_AGENT_NM(OUT_AGENT_ID) OUT_AGENT_NM, OUT_DEALER_ID, F_GET_AGENT_NM(OUT_DEALER_ID) OUT_DEALER_NM, TO_CHAR(NVL(CONTRACT_NUM,0),'9999999999') CONTRACT_NUM, RCG_FLAG, FREE_FLAG, DECODE(FREE_FLAG,'N','판매', 'Y','수수료', '-') FREE_FLAG_NM , PIN_NUMBER FROM PPS_PIN_INFO A WHERE CR_DATE > TO_DATE('1900-01-01','YYYY-MM-DD')
AND MNG_CODE LIKE '%' || #{searchNm}
AND CONTRACT_NUM = (select F_GET_LIKE_CTN2_CONTRACT_NUM(#{searchNm}) from dual)
AND PIN_NUMBER = CRYPTO_AES256.ENC_AES(#{searchNm})
AND START_PRICE = #{searchNm}
AND CR_DATE >= TO_DATE(#{startDtCreate}, 'YYYY-MM-DD')
AND CR_DATE < TO_DATE(#{endDtCreate}, 'YYYY-MM-DD')+1
AND OUT_DATE >= TO_DATE(#{startDtOut}, 'YYYY-MM-DD')
AND OUT_DATE < TO_DATE(#{endDtOut}, 'YYYY-MM-DD')+1
AND OPEN_DATE >= TO_DATE(#{startDtOpen}, 'YYYY-MM-DD')
AND OPEN_DATE < TO_DATE(#{endDtOpen}, 'YYYY-MM-DD')+1
AND EXPIRE_DATE >= TO_DATE(#{startDtExpire}, 'YYYY-MM-DD')
AND EXPIRE_DATE < TO_DATE(#{endDtExpire}, 'YYYY-MM-DD')+1
AND STATUS = #{searchPinStatus}
AND ONOFF_GUBUN = #{searchOnOffGubun}
AND OUT_AGENT_ID = #{searchAgentNm}
AND OUT_DEALER_ID = #{searchDealerNm}
AND RCG_FLAG = #{searchPinRcgFlag}
AND PIN_GUBUN = #{searchPinGubun}
AND FREE_FLAG = #{searchFreeFlag}
AND MNG_CODE LIKE #{searchManageCodeHeader} || '%'
AND MNG_CODE >= #{searchManageCodeHeader}||LPAD(#{searchManageCodeStart}, 9, '0')
AND MNG_CODE <= #{searchManageCodeHeader}||LPAD(#{searchManageCodeEnd}, 9, '0')

