AND OPEN_DATE >= TO_DATE(#{startDtOpen}, 'YYYY-MM-DD')
AND OPEN_DATE < TO_DATE(#{endDtOpen}, 'YYYY-MM-DD')+1
AND EXPIRE_DATE >= TO_DATE(#{startDtExpire}, 'YYYY-MM-DD')
AND EXPIRE_DATE < TO_DATE(#{endDtExpire}, 'YYYY-MM-DD')+1
AND STATUS = #{searchPinStatus}
AND ONOFF_GUBUN = #{searchOnOffGubun}
AND OUT_AGENT_ID = #{searchAgentNm}
AND OUT_DEALER_ID = #{searchDealerNm}
AND RCG_FLAG = #{searchPinRcgFlag}
