SELECT /*+ INDEX_DESC(A PPS_PIN_SUMMARY_CR_DATE_IDX) */ CR_SEQ, PIN_LENGTH, CR_COUNT, START_PRICE, START_MNG_CODE, END_MNG_CODE, START_MNG_CODE||'~'|| END_MNG_CODE AS MNG_CODE_STR, PIN_GUBUN, NVL(F_GET_KT_CODE_NM('PPS_PIN_SUMMARY_CREATE','PIN_GUBUN',PIN_GUBUN),'-') PIN_GUBUN_NM, ONOFF_GUBUN, NVL(F_GET_KT_CODE_NM('PPS_PIN_SUMMARY_CREATE','ONOFF_GUBUN',ONOFF_GUBUN),'-') ONOFF_GUBUN_NM, NVL(CR_ADMIN_ID,'-') CR_ADMIN_ID, NVL(F_GET_ADMIN_NM(CR_ADMIN_ID),'-') AS CR_ADMIN_NM, TO_CHAR(CR_DATE, 'YYYY-MM-DD') CR_DATE, NVL(REMARK,'-') REMARK, NVL(CANCEL_FLAG, '-') CANCEL_FLAG, DECODE(CANCEL_FLAG,'N','취소', 'Y','취소완료', '-') CANCEL_FLAG_NM , NVL(TO_CHAR(CANCEL_DATE, 'YYYY-MM-DD'), '-') CANCEL_DATE FROM PPS_PIN_SUMMARY_CREATE A WHERE CR_DATE > TO_DATE('1900-01-01','YYYY-MM-DD')
AND CR_DATE >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
