SELECT /*+ INDEX_DESC(A PPS_PIN_SUMMARY_OPEN_DATE_IDX) */ OPEN_SEQ, A.START_MNG_CODE, END_MNG_CODE, START_MNG_CODE||'~'|| END_MNG_CODE AS MNG_CODE_STR, OPEN_COUNT, PIN_CHARGE_SUM, AGENT_CHARGE_SUM, OPEN_ADMIN_ID, NVL(F_GET_ADMIN_NM(OPEN_ADMIN_ID),'-') OPEN_ADMIN_NM, NVL(TO_CHAR(OPEN_DATE, 'YYYY-MM-DD HH24:MI:SS'),'-') OPEN_DATE, OPEN_AGENT_TYPE, NVL(F_GET_KT_CODE_NM('PPS_PIN_SUMMARY_OPEN', 'OPEN_AGENT_TYPE', OPEN_AGENT_TYPE),'-') OPEN_AGENT_TYPE_NM, OPEN_AGENT_ID, NVL(FN_GET_ORGNM(OPEN_AGENT_ID),'-') OPEN_AGENT_NM, OPEN_DEALER_ID, NVL(FN_GET_ORGNM(OPEN_DEALER_ID),'-') OPEN_DEALER_NM, PAY_AMT, PAY_FLAG, NVL(TO_CHAR(PAY_DATE, 'YYYY-MM-DD'),'-') PAY_DATE, NVL(TO_CHAR(RECORD_DATE, 'YYYY-MM-DD'),'-') RECORD_DATE, NVL(REMARK,'-') REMARK, CANCEL_FLAG, DECODE(CANCEL_FLAG,'N','취소', 'Y','취소완료', '-') CANCEL_FLAG_NM , TO_CHAR(CANCEL_DATE, 'YYYY-MM-DD') CANCEL_DATE, STOP_SEQ, PIN_DIS_RATE, FREE_FLAG, DECODE(FREE_FLAG,'N','판매', 'Y','수수료', '-') FREE_FLAG_NM , '수정' AS UPD_NM_STR, NVL((SELECT TO_CHAR(MAX(OUT_DATE), 'YYYY-MM-DD HH24:MI:SS') FROM PPS_PIN_SUMMARY_OUT B WHERE B.START_MNG_CODE = A.START_MNG_CODE AND CANCEL_FLAG = 'N'),'-') OUT_DATE FROM PPS_PIN_SUMMARY_OPEN A WHERE OPEN_DATE > TO_DATE('1900-01-01','YYYY-MM-DD')
