AND START_MNG_CODE <= #{searchManageCodeHeader}||LPAD(#{searchManageCodeEnd}, 9, '0')

SELECT /*+ INDEX_DESC(A PPS_PIN_SUMMARY_OPEN_DATE_IDX) */ OPEN_SEQ, START_MNG_CODE, END_MNG_CODE, START_MNG_CODE||'~'|| END_MNG_CODE AS MNG_CODE_STR, NVL(OPEN_COUNT,0) AS OPEN_COUNT, NVL(PIN_CHARGE_SUM,0) AS PIN_CHARGE_SUM, NVL(AGENT_CHARGE_SUM,0)AS AGENT_CHARGE_SUM, NVL(OPEN_ADMIN_ID,'-') AS OPEN_ADMIN_ID, NVL(F_GET_ADMIN_NM(OPEN_ADMIN_ID),'-') AS OPEN_ADMIN_NM, NVL(TO_CHAR(OPEN_DATE, 'YYYY-MM-DD HH24:MI:SS'),'-') AS OPEN_DATE, NVL(OPEN_AGENT_TYPE,'-') AS OPEN_AGENT_TYPE, NVL(F_GET_KT_CODE_NM('PPS_PIN_SUMMARY_OPEN', 'OPEN_AGENT_TYPE', OPEN_AGENT_TYPE),'-')AS OPEN_AGENT_TYPE_NM, NVL(OPEN_AGENT_ID,'-')AS OPEN_AGENT_ID, NVL(F_GET_AGENT_NM(OPEN_AGENT_ID),'-')AS OPEN_AGENT_NM, NVL(OPEN_DEALER_ID,'-')AS OPEN_DEALER_ID, NVL(F_GET_AGENT_NM(OPEN_DEALER_ID),'-')AS OPEN_DEALER_NM, NVL(PAY_AMT,0)AS PAY_AMT, NVL(PAY_FLAG,'-')AS PAY_FLAG, NVL(TO_CHAR(PAY_DATE, 'YYYY-MM-DD'),'-') AS PAY_DATE, NVL(TO_CHAR(RECORD_DATE, 'YYYY-MM-DD'),'-') AS RECORD_DATE, NVL(REMARK,'-') AS REMARK, NVL(CANCEL_FLAG,'-')AS CANCEL_FLAG, DECODE(CANCEL_FLAG,'N','취소', 'Y','취소완료', '-')AS CANCEL_FLAG_NM , NVL(TO_CHAR(CANCEL_DATE, 'YYYY-MM-DD'),'-')AS CANCEL_DATE, NVL(STOP_SEQ,0) AS STOP_SEQ, NVL(FREE_FLAG,'-')AS FREE_FLAG, DECODE(FREE_FLAG,'N','판매', 'Y','수수료', '-') AS FREE_FLAG_NM , NVL(PIN_DIS_RATE,0)AS PIN_DIS_RATE, NVL((SELECT TO_CHAR(MAX(OUT_DATE), 'YYYY-MM-DD HH24:MI:SS') FROM PPS_PIN_SUMMARY_OUT B WHERE B.START_MNG_CODE = A.START_MNG_CODE AND CANCEL_FLAG = 'N'),'-')AS OUT_DATE FROM PPS_PIN_SUMMARY_OPEN A WHERE OPEN_DATE > TO_DATE('1900-01-01','YYYY-MM-DD')
