AND OPEN_AGENT_ID = #{searchAgentNm}
AND OPEN_DEALER_ID = #{searchDealerNm}

SELECT /*+ INDEX_DESC(A PPS_PIN_SUMMARY_OUT_DATE_IDX) */ OUT_SEQ, F_GET_PIN_COUNT('OPEN_CNT_TO_OUT', OUT_SEQ) OPEN_COUNT, START_MNG_CODE, END_MNG_CODE, START_MNG_CODE||'~'|| END_MNG_CODE AS MNG_CODE_STR, OUT_COUNT, OUT_ADMIN_ID, NVL(F_GET_ADMIN_NM(OUT_ADMIN_ID), OUT_ADMIN_ID) OUT_ADMIN_NM, TO_CHAR(OUT_DATE, 'YYYY-MM-DD') OUT_DATE, OUT_AGENT_TYPE, F_GET_KT_CODE_NM('PPS_PIN_SUMMARY_OPEN', 'OPEN_AGENT_TYPE', OUT_AGENT_TYPE) OUT_AGENT_TYPE_NM, OUT_AGENT_ID, FN_GET_ORGNM(OUT_AGENT_ID) OUT_AGENT_NM, OUT_DEALER_ID, FN_GET_ORGNM(OUT_DEALER_ID) OUT_DEALER_NM, TO_CHAR(RECORD_DATE, 'YYYY-MM-DD') RECORD_DATE, REMARK, CANCEL_FLAG, DECODE(CANCEL_FLAG,'N','취소', 'Y','취소완료', '') CANCEL_FLAG_NM , FREE_FLAG, DECODE(FREE_FLAG,'N','판매', 'Y','수수료', '-') FREE_FLAG_NM , TO_CHAR(CANCEL_DATE, 'YYYY-MM-DD') CANCEL_DATE FROM PPS_PIN_SUMMARY_OUT A WHERE OUT_DATE > TO_DATE('1900-01-01','YYYY-MM-DD')
AND OUT_DATE >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
