SELECT /*+ INDEX_DESC(A PPS_PIN_SUMMARY_OUT_DATE_IDX) */ OUT_SEQ, F_GET_PIN_COUNT('OPEN_CNT_TO_OUT', OUT_SEQ) OPEN_COUNT, START_MNG_CODE, END_MNG_CODE, START_MNG_CODE||'~'|| END_MNG_CODE AS MNG_CODE_STR, OUT_COUNT, OUT_ADMIN_ID, NVL(F_GET_ADMIN_NM(OUT_ADMIN_ID), '-') OUT_ADMIN_NM, NVL(TO_CHAR(OUT_DATE, 'YYYY-MM-DD'),'-') OUT_DATE, OUT_AGENT_TYPE, NVL(F_GET_KT_CODE_NM('PPS_PIN_SUMMARY_OPEN', 'OPEN_AGENT_TYPE', OUT_AGENT_TYPE),'-') OUT_AGENT_TYPE_NM, OUT_AGENT_ID, NVL(FN_GET_ORGNM(OUT_AGENT_ID),'-') OUT_AGENT_NM, OUT_DEALER_ID, NVL(FN_GET_ORGNM(OUT_DEALER_ID),'-') OUT_DEALER_NM, NVL(TO_CHAR(RECORD_DATE, 'YYYY-MM-DD'),'-') RECORD_DATE, NVL(REMARK,'-') REMARK, NVL(CANCEL_FLAG,'-') CANCEL_FLAG , NVL(DECODE(CANCEL_FLAG,'N','취소', 'Y','취소완료', ''),'-') CANCEL_FLAG_NM , NVL(FREE_FLAG,'-') FREE_FLAG , DECODE(FREE_FLAG,'N','판매', 'Y','수수료', '-') FREE_FLAG_NM , NVL(TO_CHAR(CANCEL_DATE, 'YYYY-MM-DD'),'-') CANCEL_DATE FROM PPS_PIN_SUMMARY_OUT A WHERE OUT_DATE > TO_DATE('1900-01-01','YYYY-MM-DD')
AND OUT_DATE >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND OUT_DATE < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND STATUS = #{searchStatus}
AND OUT_AGENT_TYPE = #{searchPinOpenAgentType}
AND FREE_FLAG = #{searchFreeFlag}
AND RECHARGE_FLAG = #{RECHARGE_FLAG}
AND CANCEL_FLAG = #{searchCancelFlag}
AND OUT_AGENT_ID = #{searchAgentNm}
AND OUT_DEALER_ID = #{searchDealerNm}
AND START_MNG_CODE LIKE #{searchManageCodeHeader} || '%'
AND END_MNG_CODE >= #{searchManageCodeHeader}||LPAD(#{searchManageCodeStart}, 9, '0')
AND START_MNG_CODE <= #{searchManageCodeHeader}||LPAD(#{searchManageCodeEnd}, 9, '0')

{CALL P_PIN_CREATE(
					#{opCode, jdbcType=VARCHAR}
					, #{crSeq, jdbcType=VARCHAR}
				    , #{pinGubun, jdbcType=VARCHAR}
				    , #{onoffGubun, jdbcType=VARCHAR}
