SELECT /*+ INDEX_DESC(A PPS_PIN_INFO_PK) */ NVL(MNG_CODE,'-') MNG_CODE, NVL(STATUS,'-') STATUS, NVL(F_GET_KT_CODE_NM('PPS_PIN_INFO', 'STATUS', STATUS),'-') STATUS_NM, NVL(PIN_GUBUN,'-') PIN_GUBUN, NVL(F_GET_KT_CODE_NM('PPS_PIN_INFO', 'PIN_GUBUN', PIN_GUBUN),'-') PIN_GUBUN_NM, NVL(ONOFF_GUBUN,'-') ONOFF_GUBUN, NVL(F_GET_KT_CODE_NM('PPS_PIN_INFO', 'ONOFF_GUBUN', ONOFF_GUBUN),'-') ONOFF_GUBUN_NM, NVL(TO_CHAR(OPEN_DATE, 'YYYY-MM-DD'),'-') OPEN_DATE, NVL(TO_CHAR(OUT_DATE, 'YYYY-MM-DD'),'-') OUT_DATE, NVL(START_PRICE,0) START_PRICE, NVL(NOW_PRICE,0) NOW_PRICE, NVL(OUT_PRICE,0) OUT_PRICE, NVL(TO_CHAR(RCG_DATE, 'YYYY-MM-DD'),'-') RCG_DATE, NVL(TO_CHAR(CR_DATE, 'YYYY-MM-DD'),'-') CR_DATE, NVL(TO_CHAR(EXPIRE_DATE, 'YYYY-MM-DD'),'-') EXPIRE_DATE, NVL(OUT_AGENT_ID,'-') OUT_AGENT_ID, NVL(F_GET_AGENT_NM(OUT_AGENT_ID),'-') OUT_AGENT_NM, NVL(OUT_DEALER_ID,'-') OUT_DEALER_ID, NVL(F_GET_AGENT_NM(OUT_DEALER_ID),'-') OUT_DEALER_NM, NVL(CONTRACT_NUM,0) CONTRACT_NUM, NVL(RCG_FLAG,'-') RCG_FLAG, NVL(FREE_FLAG,'-')FREE_FLAG, DECODE(FREE_FLAG,'N','판매', 'Y','수수료', '-') AS FREE_FLAG_NM, NVL(PIN_NUMBER,'-') PIN_NUMBER FROM PPS_PIN_INFO WHERE CR_DATE > TO_DATE('1900-01-01','YYYY-MM-DD')
AND MNG_CODE BETWEEN #{startMngCode} AND #{endMngCode}
ORDER BY MNG_CODE ASC
